        if (tileLen == 0) tileLen = totalSpatial;
    }

    uint32_t numTiles = CeilDiv(totalSpatial, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    tiling.totalLength_ = totalLength;
    tiling.tileLength_ = tileLen;
    tiling.blockDim_ = blockDim;
    tiling.C_ = C;
    tiling.H_ = H;
    tiling.W_ = W;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    tiling.normSize_ = attrs->GetAttrPointer<int>(0)[0];
    tiling.alpha_ = attrs->GetAttrPointer<float>(1)[0];
    tiling.beta_ = attrs->GetAttrPointer<float>(2)[0];
    tiling.k_ = attrs->GetAttrPointer<float>(3)[0];

    context->SetBlockDim(blockDim);
    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}
