#include "kernel_operator.h"
#include <cmath>

class KernelCa6k00449Custom {
public:
    __aicore__ inline KernelCa6k00449Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t C, uint32_t H, uint32_t W,
                                uint32_t normSize, float alpha, float beta, float k) {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        C_ = C;
        H_ = H;
        W_ = W;
        normSize_ = normSize;
        alpha_ = alpha;
        beta_ = beta;
        k_ = k;
        halfWin_ = normSize_ / 2;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
    }

    __aicore__ inline void Process() {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        uint32_t spatialPerBatch = H_ * W_;
        uint32_t totalSpatial = totalLen_ / C_;

        uint32_t strideTiles = blockNum;
        uint32_t tileCount = (totalSpatial + tileLen_ - 1) / tileLen_;

        for (uint32_t tileIdx = blockIdx; tileIdx < tileCount; tileIdx += strideTiles) {
            uint32_t spatialStart = tileIdx * tileLen_;
            uint32_t curSpatialLen = totalSpatial - spatialStart;
            if (curSpatialLen > tileLen_) curSpatialLen = tileLen_;

            // Process each spatial element individually
            for (uint32_t s = 0; s < curSpatialLen; ++s) {
                uint32_t spatialIdx = spatialStart + s;
                uint32_t batch = spatialIdx / spatialPerBatch;
                uint32_t posInBatch = spatialIdx % spatialPerBatch;

                // Load all C channels for this spatial position
                float xVals[256];  // max C = 256 (assuming)
                for (uint32_t c = 0; c < C_; ++c) {
                    uint32_t gmIdx = batch * C_ * spatialPerBatch + c * spatialPerBatch + posInBatch;
                    xVals[c] = xGm_.GetValue(gmIdx);
                }

                // Compute squared
                float sqVals[256];
                for (uint32_t c = 0; c < C_; ++c) {
                    sqVals[c] = xVals[c] * xVals[c];
                }

                // Compute window sum and output for each channel
                float yVals[256];
                for (uint32_t c = 0; c < C_; ++c) {
                    float sum = 0.0f;
                    int start = (int)c - (int)halfWin_;
                    if (start < 0) start = 0;
                    int end = (int)c + (int)halfWin_;
                    if (end >= (int)C_) end = C_ - 1;
                    for (int j = start; j <= end; ++j) {
                        sum += sqVals[j];
                    }
                    float denom = powf(k_ + alpha_ * sum, beta_);
                    yVals[c] = xVals[c] / denom;
                }

                // Write back
                for (uint32_t c = 0; c < C_; ++c) {
                    uint32_t gmIdx = batch * C_ * spatialPerBatch + c * spatialPerBatch + posInBatch;
                    yGm_.SetValue(gmIdx, yVals[c]);
                }
            }
        }
    }

private:
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_{0};
    uint32_t tileLen_{0};
    uint32_t C_{0};
    uint32_t H_{0};
    uint32_t W_{0};
    uint32_t normSize_{0};
    uint32_t halfWin_{0};
    float alpha_{0.0f};
    float beta_{0.0f};
    float k_{2.0f};
};

extern "C" __global__ __aicore__ void ca6k_00449_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00449Custom op;
    op.Init(x, y,
            tiling_data.totalLength_, tiling_data.tileLength_,
            tiling_data.C_, tiling_data.H_, tiling_data.W_,
            tiling_data.normSize_, tiling_data.alpha_, tiling_data.beta_, tiling_data.k_);
    op.Process();
}
